#include <bits/stdc++.h>
using namespace std;
int main(){
    string a,s;
    cin>>a;
    getline(cin,s);
    getline(cin,s);
    for(int i=0;i<a.size();i++)if(a[i]>='A' && a[i]<='Z')a[i]+=('a'-'A');
    for(int i=0;i<s.size();i++)if(s[i]>='A' && s[i]<='Z')s[i]+=('a'-'A');
    s=" "+s+" ";
    a=" "+a+" ";
    if(s.find(a)==string::npos){
        cout<<-1;
        return 0;
    }
    int i=0,sum=0;
    while(s.find(a,i)!=string::npos && i<s.size()){
        sum++;
        i=s.find(a,i)+1;
    }
    cout<<sum<<' '<<s.find(a);
    return 0;
}
